  /* ─── USAGE · DAILY breakdown for last 30d ──────────────── */
  /* By-model per-day requests, aligned to usage.sparkline_30d total */
  usage_30d: (function(){
    const totals = [ 412, 438, 461, 487, 502, 498, 476, 512, 548, 571, 604, 612, 588, 542, 519, 546, 582, 610, 648, 691, 728, 702, 684, 719, 753, 781, 798, 812, 796, 824 ];
    // mix: allam 42%, llama 36%, bge 12%, falcon 10%  — add ± jitter but stay deterministic
    return totals.map((r, i) => {
      const j = (i * 7 + 3) % 11;
      const allam  = Math.round(r * (0.40 + j*0.005));
      const llama  = Math.round(r * (0.36 - j*0.003));
      const bge    = Math.round(r * (0.12 + ((i*3)%7 - 3)*0.004));
      const falcon = Math.max(1, r - allam - llama - bge);
      return { day: i+1, total: r, allam, llama, bge, falcon };
    });
  })(),

